662	func intakeResultPayload(result *Result) (string, error) {
663		if result == nil {
664			return "", fmt.Errorf("pre-claim intake: empty runner result")
665		}
666		text := strings.TrimSpace(result.CondensedOutput)
667		if text == "" {
668			text = strings.TrimSpace(result.Output)
669		}
670		if text == "" {
671			if strings.TrimSpace(result.Error) != "" {
672				return "", fmt.Errorf("pre-claim intake: runner error: %s", strings.TrimSpace(result.Error))
673			}
674			if result.ExitCode != 0 {
675				return "", fmt.Errorf("pre-claim intake: runner exited with code %d and empty output", result.ExitCode)
676			}
677			return "", fmt.Errorf("pre-claim intake: empty output")
678		}
679		candidate, ok := extractJSONCandidate(text)
680		if !ok {
681			return "", fmt.Errorf("pre-claim intake: no JSON object found")
682		}
683		return candidate, nil
684	}
